// categoryOrder defines the display order for rule categories.
var categoryOrder = map[string]int{
	"setup":            0,
	"economy":          1,
	"power":            2,
	"tech":             3,
	"produce_building": 4,
	"produce_defense":  5,
	"produce_infantry": 6,
	"produce_vehicle":  7,
	"produce_air":      8,
	"produce_naval":    9,
	"combat":           10,
	"micro":            11,
	"recon":            12,
	"capture":          13,
	"superweapon":      14,
}

func groupAndSortRules(summaries []rules.RuleSummary) []categoryGroup {
	grouped := make(map[string][]rules.RuleSummary)
	for _, s := range summaries {
		grouped[s.Category] = append(grouped[s.Category], s)
	}
	var groups []categoryGroup
	for cat, rs := range grouped {
		groups = append(groups, categoryGroup{Category: cat, Rules: rs})
	}
	sort.Slice(groups, func(i, j int) bool {
		oi, oki := categoryOrder[groups[i].Category]
		oj, okj := categoryOrder[groups[j].Category]
		if !oki {
			oi = 100
		}
		if !okj {
			oj = 100
		}
		if oi != oj {
			return oi < oj
		}
		return groups[i].Category < groups[j].Category
	})
	return groups
}

type categoryGroup struct {
	Category string
	Rules    []rules.RuleSummary
}

